# name: max_run_b_choice_correlation
# description: Pearson correlation between max_run_norm_b and chose_left; tests whether longer B runs monotonically increase the probability of choosing A, probing max-run as a salience cue absent from the model.
def test_statistic(df):
    r = np.corrcoef(df['max_run_norm_b'].values, df['chose_left'].values)[0, 1]
    return float(r)

# name: low_max_run_b_choice_rate
# description: Mean chose_left when max_run_norm_b < 0.2 (B has only very short runs, appears locally balanced); tests if humans judge B as more random when it lacks salient streaks.
def test_statistic(df):
    mask = df['max_run_norm_b'] < 0.2
    sub = df[mask]
    if len(sub) == 0:
        return float('nan')
    return float(sub['chose_left'].mean())

# name: head_imbalance_b_choice_rate
# description: Mean chose_left when imbalance_b > 0.3 and imbalance_a < 0.1 (B is head-biased, A is balanced); tests calibration of the biased-coin component by isolating trials where B's head proportion clearly departs from 0.5.
def test_statistic(df):
    mask = (df['imbalance_b'] > 0.3) & (df['imbalance_a'] < 0.1)
    sub = df[mask]
    if len(sub) == 0:
        return float('nan')
    return float(sub['chose_left'].mean())

